INSERT INTO TBL_SCHEDULE_PUBLIC_DEPT(
	USERCN, 		USERNAME, 		USERNAME2, 		DEPARTMENTCN, 	DEPARTMENTNAME, 	DEPARTMENTNAME2,	TENANT_ID 	 , companyID
) VALUES (
	#v_USERID#,		#v_USERNAME#,	#v_USERNAME2#,	#v_DEPTID#,		#v_DEPTNAME#,		#v_DEPTNAME2#,		#v_TENANTID#	,		#v_COMPANYID#	
)


INSERT INTO TBL_HOLIDAYLIST(
	HOLIDAYNAME,		HOLIDAYNAME2, 		HOLIDAYFLAG,		HOLIDAYDATE, 		HOLIDAYREPEAT, 		ISSOLAR, 		ISREPEAT, 		ISUSE, 		ISREST, 		USECOMPANY,			TENANT_ID 
) VALUES (
	#v_HOLIDAYNAME#,	#v_HOLIDAYNAME2#,	#v_HOLIDAYFLAG#,	TO_DATE(#v_HOLIDAYDATE#, 'yyyy-MM-dd'),	#v_HOLIDAYREPEAT#,	#v_ISSOLAR#,	#v_ISREPEAT#,	1,			#v_ISREST#, 	#v_COMPANYID#,		#v_TENANTID#		
)


SELECT SEQ_TBL_HOLIDAYLIST.currval FROM dual


INSERT INTO TBL_LUNARUSE(
	USECOMPANY,			LUNARUSE, 			TENANT_ID 
) VALUES (
	#v_COMPANYID#,		#v_LUNARUSE#,		#v_TENANTID#
)


INSERT INTO TBL_PREVIOSLYREGI(
	USECOMPANY,			PREVIOSLYREGIUSE, 	TENANT_ID 
) VALUES (
	#v_COMPANYID#,		#v_REGI#,			#v_TENANTID#
)
